#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;
typedef pair<int,int> pii;

const int N=2e5+10;

int T,n,m,t[N],p[N];
pii a[N],b[N];
bool use[N];
long long ans;

int main(){
    scanf("%d",&T);
    while(T--){
        ans=0;
        scanf("%d%d",&n,&m);
        for(int i=1;i<=n;i++){
            scanf("%d",&a[i].x);
            a[i].y=i;
            a[i].x%=m;
            ans+=a[i].x;
            p[i]=use[i]=0;
        }
        for(int i=1;i<=n;i++){
            scanf("%d",&b[i].x);
            b[i].y=i;
            t[i]=b[i].x;
            b[i].x%=m;
            ans+=b[i].x;
        }
        sort(a+1,a+n+1);
        sort(b+1,b+n+1);
        for(int i=1,j=n;i<=n;i++){
            while(j && a[i].x+b[j].x>=m)
                j--;
            if(j){
                p[a[i].y]=b[j].y;
                use[b[j].y]=1;
                j--;
            }else{
                for(int k=i,l=1;k<=n;k++){
                    while(use[l])
                        l++;
                    p[a[k].y]=l;
                    use[l]=1;
                }
                ans-=1ll*(n-i+1)*m;
                break;
            }
        }
        printf("%lld\n",ans);
        for(int i=1;i<=n;i++)
            printf("%d ",t[p[i]]);
        puts("");
    }
    return 0;
}
